In C++, to craft an optimal code for calculating the derivative of a mathematical function, we must first understand the nature of the function. For simplicity, let's assume we're dealing with polynomials of the form \( f(x) = a_nx^n + a_{n-1}x^{n-1} + \ldots + a_1x + a_0 \). The derivative of such a polynomial is straightforward: \( f'(x) = n*a_n*x^{n-1} + (n-1)*a_{n-1}*x^{n-2} + \ldots + 1*a_1 \).

To achieve this in C++, we'll define a class `Polynomial` that can store coefficients and perform differentiation. We'll use dynamic arrays for flexibility and efficiency.

```cpp
#include <iostream>
#include <vector>

class Polynomial {
private:
    std::vector<double> coefficients;

public:
    // Constructor to initialize the polynomial with coefficients
    Polynomial(std::vector<double> coeffs) : coefficients(coeffs) {}

    // Method to calculate the derivative
    Polynomial derivative() const {
        std::vector<double> derivedCoefficients;
        for (size_t i = 1; i < coefficients.size(); ++i) {
            derivedCoefficients.push_back(i * coefficients[i]);
        }
        return Polynomial(derivedCoefficients);
    }

    // Method to print the polynomial
    void print() const {
        for (size_t i = 0; i < coefficients.size(); ++i) {
            std::cout << coefficients[i] << "x^" << (int)(coefficients.size() - 1 - i) << " ";
        }
        std::cout << std::endl;
    }
};

// Main function to demonstrate the usage
int main() {
    std::vector<double> coeffs = {3, 2, 1}; // Represents 3x^2 + 2x + 1
    Polynomial poly(coeffs);

    std::cout << "Original Polynomial: ";
    poly.print();

    Polynomial derivedPoly = poly.derivative();
    std::cout << "Derivative Polynomial: ";
    derivedPoly.print();

    return 0;
}
```

